// Get all input items from both APIs
const items = $input.all();

if (items.length === 0) {
  return [];
}

// Track which sources detected risk
const sources = [];
let timestamp = new Date().toISOString();

items.forEach((item, index) => {
  // Determine source based on position (0 = Open-Meteo, 1 = Google)
  if (index === 0) {
    sources.push('Open-Meteo');
  } else if (index === 1) {
    sources.push('Google Weather');
  }
});

// Return single consolidated alert
return [{
  json: {
    alert: true,
    severity: sources.length > 1 ? 'high' : 'moderate',
    sources: sources,
    sourcesCount: sources.length,
    message: sources.length > 1 
      ? `⚠️ Multiple weather sources (${sources.join(', ')}) detected storm/hail risk!`
      : `⚠️ ${sources[0]} detected storm/hail risk!`,
    timestamp: timestamp,
    location: 'NYC (40.7128, -74.0060)',
    actionRequired: 'Stay indoors and monitor local weather updates'
  }
}];

