// Get error details from the trigger
const error = $input.first().json;

// Format error message
const workflowName = error.workflow.name || 'Unknown';
const nodeName = error.execution.lastNodeExecuted || 'Unknown';
const errorMessage = error.execution.error?.message || 'No details available';
const executionId = error.execution.id;
const timestamp = new Date().toISOString();

return [{
  json: {
    errorAlert: true,
    workflow: workflowName,
    failedNode: nodeName,
    message: errorMessage,
    executionId: executionId,
    timestamp: timestamp,
    formattedMessage: `🔴 WORKFLOW ERROR\n\nWorkflow: ${workflowName}\nFailed Node: ${nodeName}\nError: ${errorMessage}\nExecution ID: ${executionId}\nTime: ${new Date(timestamp).toLocaleString('en-US', { timeZone: 'America/New_York' })}\n\n⚠️ Please check the workflow and fix the issue.`
  }
}];
